    var dsecret = sessionSecretFor(dcode, cache, props);
    if (!dsecret) return out({ ok: false, e: 'no-session' });
    var dactor = requestActor(p, dcode, dsecret, admin);
    if (!dactor) return out({ ok: false, e: 'denied' });
