  const playSound = useCallback((type) => {
      if (alloBotRef.current) {
          if (type === 'correct') alloBotRef.current.triggerReaction('🎉');
          else if (type === 'incorrect') alloBotRef.current.triggerReaction('❌');
          else if (type === 'reveal') alloBotRef.current.triggerReaction('👀');
      }
      if (!soundEnabled) return;
      try {
          const ctx = getGlobalAudioContext();
          if (!ctx) return;
          if (ctx.state === 'suspended') {
              ctx.resume();
          }
          const osc = ctx.createOscillator();
          const gain = ctx.createGain();
          osc.connect(gain);
          gain.connect(ctx.destination);
          const now = ctx.currentTime;
          if (type === 'correct') {
              osc.type = 'sine';
              osc.frequency.setValueAtTime(500, now);
              osc.frequency.exponentialRampToValueAtTime(1000, now + 0.1);
              gain.gain.setValueAtTime(0.2, now);
              gain.gain.exponentialRampToValueAtTime(0.01, now + 0.6);
              osc.start(now);
              osc.stop(now + 0.6);
          } else if (type === 'incorrect') {
              osc.type = 'sawtooth';
              osc.frequency.setValueAtTime(150, now);
              osc.frequency.linearRampToValueAtTime(100, now + 0.3);
              gain.gain.setValueAtTime(0.2, now);
              gain.gain.exponentialRampToValueAtTime(0.01, now + 0.4);
              osc.start(now);
              osc.stop(now + 0.4);
          } else if (type === 'reveal') {
              osc.type = 'triangle';
              osc.frequency.setValueAtTime(200, now);
              osc.frequency.exponentialRampToValueAtTime(600, now + 0.2);
              gain.gain.setValueAtTime(0.1, now);
              gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);
              osc.start(now);
              osc.stop(now + 0.3);
          } else if (type === 'click') {
              osc.type = 'sine';
              osc.frequency.setValueAtTime(800, now);
              gain.gain.setValueAtTime(0.05, now);
              gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
              osc.start(now);
              osc.stop(now + 0.1);
          } else if (type === 'bell') {
              osc.type = 'sine';
              osc.frequency.setValueAtTime(880, now);
              gain.gain.setValueAtTime(0, now);
              gain.gain.linearRampToValueAtTime(0.3, now + 0.01);
              gain.gain.exponentialRampToValueAtTime(0.001, now + 1.5);
              osc.start(now);
              osc.stop(now + 1.5);
          }
      } catch (e) {
          warnLog("Audio play error", e);
      }
  }, [soundEnabled]);
