      const answered = Object.keys(qs.responses || {}).length;
      const total = Object.keys((sessionData.roster) || {}).length;
      const key = String(qs.currentQuestionIndex) + ':' + answered + '/' + total;
      if (quizProgressSentRef.current === key) return;
