  const getAdaptiveDifficulty = React.useCallback(() => {
    if (exploreScore.total < 3) return exploreDifficulty;
    const pct = exploreScore.correct / exploreScore.total;
    if (pct >= 0.85) return 'hard';
    if (pct <= 0.4) return 'easy';
    return 'medium';
  }, [exploreScore, exploreDifficulty]);
  const submitExploreScore = React.useCallback(() => {
    if (exploreScore.total === 0) return;
    const pct = Math.round((exploreScore.correct / exploreScore.total) * 100);
    const entry = {
      type: 'explore-challenge',
      tool: stemLabTool || 'mixed',
      correct: exploreScore.correct,
      total: exploreScore.total,
      percentage: pct,
      date: new Date().toISOString(),
      label: 'Explore Challenge: ' + (stemLabTool || 'mixed') + ' (' + exploreScore.correct + '/' + exploreScore.total + ')'
    };
    setHistory(prev => [...prev, entry]);
    if (typeof addToast === 'function') addToast(t('toasts.explore_score_saved') + exploreScore.correct + '/' + exploreScore.total + ' (' + pct + '%)', 'success');
    setExploreScore({ correct: 0, total: 0 });
  }, [exploreScore, stemLabTool]);
