        let newY = currentY;
        if (node.type === 'flow-start') {
            newY = 50;
            currentY = 150;
        } else if (node.type === 'flow-end') {
            newY = currentY + 50;
        } else if (node.type === 'flow-note') {
            newX = centerX + 200;
            newY = currentY - 80;
        } else {
            newY = currentY;
            currentY += 120;
        }
