                          const msg = entry && entry[1];
                          const v = msg && msg.v;
                          if (!v) continue;
                          if (v.kind === 'student') applyStudentUpdate(v, msg.t);
                          else if (v.kind === 'hw-evidence') applyHwEvidence(v);
                          else if (v.kind === 'rtc') await answerRtcOffer(v);
