      <ErrorBoundary fallbackMessage="File transcription encountered an error. Please try again.">
      <LargeFileTranscriptionModal
        isOpen={showLargeFileModal}
        file={pendingLargeFile}
        onClose={() => {
            if (!isLargeFileProcessing) {
                setShowLargeFileModal(false);
                setPendingLargeFile(null);
                LargeFileHandler.cancel();
            }
        }}
        onConfirm={async () => {
            if (!pendingLargeFile) return;
            const documentIntakeEpoch = capturePdfDocumentIntakeEpoch();
            setIsLargeFileProcessing(true);
            setLargeFileProgress(0);
            setLargeFileStatus(t('large_file.starting') || 'Starting...');
            try {
                const fileType = LargeFileHandler.getFileType(pendingLargeFile);
                const processMethod = fileType === 'video'
                    ? LargeFileHandler.processVideoFile.bind(LargeFileHandler)
                    : LargeFileHandler.processAudioFile.bind(LargeFileHandler);
                const result = await processMethod(
                    pendingLargeFile,
                    async (base64, mimeType) => {
                        const prompt = `
                            You are an expert educational transcriber.
                            Listen to this audio file.
                            Provide a comprehensive, accurate transcript of the spoken content.
                            Format it as clear text suitable for use as source material.
                        `;
                        return await callGeminiVision(prompt, base64, mimeType);
                    },
                    (current, total, status) => {
                        if (!isPdfDocumentIntakeCurrent(documentIntakeEpoch)) return;
                        setLargeFileProgress(current);
                        setLargeFileTotalChunks(total);
                        setLargeFileStatus(status);
                    }
                );
                if (!isPdfDocumentIntakeCurrent(documentIntakeEpoch)) return;
                if (result && result.transcript) {
                    setInputText(prev => prev + '\n\n' + result.transcript);
                    addToast(t('toasts.file_chunking_complete') || 'Transcription complete!', 'success');
                }
            } catch (error) {
                if (!isPdfDocumentIntakeCurrent(documentIntakeEpoch)) return;
                if (error.message !== 'Cancelled') {
                    warnLog('Large file transcription error:', error);
                    addToast(t('toasts.file_chunking_failed') || 'Chunked transcription failed.', 'error');
                }
            } finally {
                if (!isPdfDocumentIntakeCurrent(documentIntakeEpoch)) return;
                setIsLargeFileProcessing(false);
                setShowLargeFileModal(false);
                setPendingLargeFile(null);
                setLargeFileProgress(0);
                setLargeFileTotalChunks(0);
                setLargeFileStatus('');
            }
        }}
        progress={largeFileProgress}
        totalChunks={largeFileTotalChunks}
        status={largeFileStatus}
        isProcessing={isLargeFileProcessing}
        t={t}
      />
      </ErrorBoundary>
